def _fatal(msg):
    """Show a popup that stays open regardless of how the exe was launched."""
    try:
        _ctypes.windll.user32.MessageBoxW(
            0, str(msg)[:2000], "MultiFMacro — Fatal Error", 0x10)
    except Exception:
        pass
    try:
        input("\nPress Enter to close...")
    except Exception:
        pass
    sys.exit(1)

