    def _check_dep(import_name):
        """Return True if the package is already importable."""
        import importlib
        try:
            importlib.import_module(import_name)
            return True
        except ImportError:
            return False

    def _install_deps(python_exe, status_cb=None):
        """
        Install any missing deps using pip.
        status_cb(msg, color) updates UI.
        Returns (installed_count, failed_list).
        """
        import subprocess as _sp
        missing = [pip for imp, pip in _DEPS.items() if not _check_dep(imp)]
        if not missing:
            if status_cb: status_cb("✓ All dependencies already installed", "green")
            return 0, []
        failed = []
        for i, pkg in enumerate(missing):
            if status_cb: status_cb(f"Installing {pkg}… ({i+1}/{len(missing)})", "cyan")
            try:
                result = _sp.run(
                    [python_exe, "-m", "pip", "install", "--quiet", "--upgrade", pkg],
                    capture_output=True, text=True, timeout=120
                )
                if result.returncode != 0:
                    failed.append(pkg)
                    print(f"[Deps] pip failed for {pkg}: {result.stderr[:200]}")
                else:
                    print(f"[Deps] installed {pkg}")
            except Exception as e:
                failed.append(pkg)
                print(f"[Deps] error installing {pkg}: {e}")
        return len(missing) - len(failed), failed

