    def _parse_version(v):
        try:
            return tuple(int(x) for x in v.strip().lstrip("vV").split("."))
        except Exception:
            return (0,)

    def check_for_update():
        """Check GitHub for a newer release. Returns (tag, exe_url, size) or None."""
        try:
            r = requests.get(GITHUB_API, timeout=8,
                             headers={"Accept": "application/vnd.github+json",
                                      "X-GitHub-Api-Version": "2022-11-28"})
            r.raise_for_status()
            data = r.json()
            tag = data.get("tag_name", "").strip()
            print(f"[Updater] Latest: {tag!r}  Local: {VERSION!r}")
            if not tag:
                return None
            if _parse_version(tag) <= _parse_version(VERSION):
                print("[Updater] Already up to date")
                return None
            print(f"[Updater] Update available: {tag}")
            assets = data.get("assets", [])
            print(f"[Updater] Assets: {[a['name'] for a in assets]}")
            for asset in assets:
                if asset["name"].lower().endswith(".exe"):
                    return tag, asset["browser_download_url"], asset.get("size", 0)
            print("[Updater] No .exe asset attached to this release")
            return None
        except Exception as e:
            print(f"[Updater] check failed: {e}")
            return None

    def do_update(tag, url, total_size=0, status_var=None, bar=None, win=None):
        """
        Download the .exe asset, then use a .bat script to replace the running
        exe and restart it (Windows cannot overwrite a running process directly).
        """
        import tempfile, subprocess as _sp

        def _set(msg):
            if status_var:
                try:
                    status_var.set(msg)
                    if win: win.update()
                except Exception:
                    pass

        try:
            _set(f"Downloading {os.path.basename(url)}...")
            r = requests.get(url, timeout=120, stream=True)
            r.raise_for_status()
            total = int(r.headers.get("content-length", total_size or 1))
            downloaded = 0

            tmp_fd, tmp_path = tempfile.mkstemp(suffix=".exe",
                                                 dir=os.path.dirname(CURRENT_FILE))
            with os.fdopen(tmp_fd, "wb") as f:
                for chunk in r.iter_content(chunk_size=65536):
                    if chunk:
                        f.write(chunk)
                        downloaded += len(chunk)
                        if bar:
                            try:
                                bar["value"] = min(99, downloaded / total * 100)
                                if win: win.update()
                            except Exception:
                                pass

            if bar:
                try: bar["value"] = 100
                except Exception: pass
            _set("Installing — restarting in a moment...")

            # Write helper bat: wait for this process to fully exit, swap files, relaunch
            bat = os.path.join(tempfile.gettempdir(), "_mfm_update.bat")
            with open(bat, "w") as bf:
                bf.write("@echo off\r\n")
                # Wait until the exe is no longer locked (up to ~10s)
                bf.write(f":wait\r\n")
                bf.write(f"move /y \"{tmp_path}\" \"{CURRENT_FILE}\" >nul 2>&1\r\n")
                bf.write("if errorlevel 1 (\r\n")
                bf.write("    ping -n 2 127.0.0.1 >nul\r\n")
                bf.write("    goto wait\r\n")
                bf.write(")\r\n")
                bf.write(f"start \"\" \"{CURRENT_FILE}\"\r\n")
                bf.write("del \"%~f0\"\r\n")

            _sp.Popen(["cmd", "/c", bat],
                      creationflags=_sp.CREATE_NO_WINDOW if os.name == "nt" else 0)

            # Force-kill this process from the main thread so the exe lock is released
            if win:
                try: win.update()
                except Exception: pass
            try:
                root = tk._default_root
                if root: root.after(0, lambda: os._exit(0))
                else: os._exit(0)
            except Exception:
                os._exit(0)

        except Exception as e:
            _set(f"Update failed: {e}")

    def run_updater():
        """Background startup check — prompts if a newer version exists."""
        def _check():
            result = check_for_update()
            if not result:
                return
            tag, url, size = result
            def _ask():
                if messagebox.askyesno(
                    "Update Available",
                    f"MultiFMacro {tag} is available (you have {VERSION}).\n\nDownload and install now?",
                    icon="info"
                ):
                    do_update(tag, url, size)
            try:
                root = tk._default_root
                if root: root.after(0, _ask)
                else: _ask()
            except Exception:
                _ask()
        threading.Thread(target=_check, daemon=True).start()
