    # ── pyautogui helpers ─────────────────────────────────────────────────────
    def _activate_roblox():
        try:
            import ctypes
            hwnd = ctypes.windll.user32.FindWindowW(None,"Roblox")
            if hwnd: ctypes.windll.user32.SetForegroundWindow(hwnd)
            time.sleep(0.3)
        except: time.sleep(0.3)

    def _click(x, y, d=0.3):
        if not PAG_OK: return
        pyautogui.moveTo(x, y, duration=0.15)
        pyautogui.click()
        time.sleep(d)

    def _paste(text):
        """Paste text via clipboard — works with spaces and special chars."""
        import pyperclip
        pyperclip.copy(str(text))
        pyautogui.hotkey("ctrl","v")
        time.sleep(0.2)

    def do_anti_kick():
        """
        Press Space in Roblox to prevent idle kick.
        Uses PostMessage (WM_KEYDOWN/WM_KEYUP) sent directly to the Roblox
        window handle so it works even when Roblox is not the foreground window.
        Falls back to pyautogui if the window handle can't be found.
        """
        VK_SPACE   = 0x20
        WM_KEYDOWN = 0x0100
        WM_KEYUP   = 0x0101

        try:
            import ctypes
            import ctypes.wintypes

            # Find the Roblox window — try both common titles
            hwnd = None
            for title in ("Roblox", "ROBLOX"):
                hwnd = ctypes.windll.user32.FindWindowW(None, title)
                if hwnd:
                    break

            # Also try EnumWindows to find any window whose title contains "Roblox"
            if not hwnd:
                found = ctypes.c_ulong(0)
                def _enum_cb(h, _):
                    buf = ctypes.create_unicode_buffer(256)
                    ctypes.windll.user32.GetWindowTextW(h, buf, 256)
                    if "roblox" in buf.value.lower():
                        found.value = h
                        return False   # stop enumeration
                    return True
                WNDENUMPROC = ctypes.WINFUNCTYPE(ctypes.c_bool, ctypes.c_ulong, ctypes.c_ulong)
                ctypes.windll.user32.EnumWindows(WNDENUMPROC(_enum_cb), 0)
                hwnd = found.value

            if hwnd:
                # PostMessage is non-blocking and doesn't require foreground focus
                ctypes.windll.user32.PostMessageW(hwnd, WM_KEYDOWN, VK_SPACE, 0)
                time.sleep(0.1)
                ctypes.windll.user32.PostMessageW(hwnd, WM_KEYUP,   VK_SPACE, 0)
                print(f"[AntiKick] Space sent via PostMessage to hwnd={hwnd}")
                return
        except Exception as e:
            print(f"[AntiKick] PostMessage failed: {e}")

        # Fallback: pyautogui (requires foreground focus)
        if not PAG_OK:
            print("[AntiKick] pyautogui not available")
            return
        try:
            _activate_roblox()
            pyautogui.keyDown("space")
            time.sleep(0.1)
            pyautogui.keyUp("space")
            print("[AntiKick] Space sent via pyautogui")
        except Exception as e:
            print(f"[AntiKick] pyautogui fallback failed: {e}")

    # Relative coords as fractions of the Roblox window (1920x1080 reference).
    # These work in ANY resolution and both fullscreen and windowed mode.
    AHK_ITEM_REL = {
        "open_inventory": (46/1920,  520/1080),
        "items_btn":      (1279/1920, 342/1080),
        "search_bar":     (1104/1920, 368/1080),
        "first_item":     (848/1920,  479/1080),
        "use_item":       (682/1920,  578/1080),
        "close_menu":     (1413/1920, 297/1080),
    }

    def _get_roblox_window():
        """Return (x, y, w, h) of the Roblox window, or None if not found."""
        try:
            import ctypes
            hwnd = ctypes.windll.user32.FindWindowW(None, "Roblox")
            if not hwnd:
                return None
            rect = ctypes.wintypes.RECT()
            ctypes.windll.user32.GetClientRect(hwnd, ctypes.byref(rect))
            pt = ctypes.wintypes.POINT(0, 0)
            ctypes.windll.user32.ClientToScreen(hwnd, ctypes.byref(pt))
            w = rect.right - rect.left
            h = rect.bottom - rect.top
            if w < 100 or h < 100:
                return None
            return pt.x, pt.y, w, h
        except Exception:
            return None

    def _rel_click(key, D=0.3):
        """Click a relative coord key, scaled to actual Roblox window size/position."""
        rx, ry = AHK_ITEM_REL[key]
        win = _get_roblox_window()
        if win:
            wx, wy, ww, wh = win
            x = int(wx + rx * ww)
            y = int(wy + ry * wh)
        else:
            # Fallback: use raw 1920x1080 absolute coords (fullscreen)
            sw, sh = get_screen_size()
            x = int(rx * sw)
            y = int(ry * sh)
        pyautogui.moveTo(x, y, duration=0.1)
        pyautogui.click()
        time.sleep(D)

    def use_item(item_name, amount, cb=None):
        """
        Use an inventory item. Works in both fullscreen and windowed Roblox.
        Coords are relative to the Roblox client window so resolution/mode doesn't matter.
        Steps: open_inventory -> items_btn -> search_bar -> paste name ->
               first_item -> use_item -> close_menu
        """
        def st(m):
            if cb: cb(m)
        if not PAG_OK: st("pyautogui not installed"); return False
        D = 0.3
        try:
            _activate_roblox()
            st(f"Using {item_name}...")
            _rel_click("open_inventory", D)
            _rel_click("items_btn",      D)
            _rel_click("search_bar",     D)
            _paste(item_name); time.sleep(D)
            _rel_click("first_item",     D)
            _rel_click("use_item",       D)
            _rel_click("close_menu",     D)
            st(f"✓ Used {item_name}"); return True
        except Exception as e:
            st(f"Error: {e}")
            try:
                _rel_click("close_menu", 0)
            except: pass
            return False
