            def _make_resize(cursor, x_dir, y_dir):
                h = tk.Frame(self.root, bg=BG0, cursor=cursor)
                h._rx = h._ry = 0
                def _rds(e): h._rx=e.x_root; h._ry=e.y_root; h._w=self.root.winfo_width(); h._h=self.root.winfo_height(); h._wx=self.root.winfo_x(); h._wy=self.root.winfo_y()
                def _rdm(e):
                    dx=e.x_root-h._rx; dy=e.y_root-h._ry
                    nw=max(700,h._w+dx*x_dir); nh=max(420,h._h+dy*y_dir)
                    nx=h._wx+(h._w-nw) if x_dir<0 else h._wx
                    ny=h._wy+(h._h-nh) if y_dir<0 else h._wy
                    self.root.geometry(f"{nw}x{nh}+{nx}+{ny}")
                h.bind("<ButtonPress-1>",_rds); h.bind("<B1-Motion>",_rdm)
