        def _build_webhook_tab(self):
            outer = tk.Frame(self.content_area, bg=BG1); self._reg("WEBHOOK", outer)
            outer.columnconfigure(0, weight=1); outer.columnconfigure(1, weight=1)
            outer.rowconfigure(0, weight=1)

