            mcf = tk.Frame(moc, bg=BG2); mcf.grid(row=5, column=0, columnspan=4, sticky="w", padx=12, pady=(8,2))
            tk.Label(mcf, text="Chat region:", bg=BG2, fg=TXT3, font=FONT_LABEL).pack(side="left")
            tk.Label(mcf, textvariable=self._ocr_coord_var, bg=BG2, fg=ACC2, font=FONT_MONO).pack(side="left", padx=(6,0))

            msf = tk.Frame(moc, bg=BG2); msf.grid(row=6, column=0, columnspan=4, sticky="w", padx=12, pady=(2,8))
            tk.Label(msf, textvariable=self._ocr_scan_status, bg=BG2, fg=GOLD, font=FONT_LABEL).grid(row=1, column=0, columnspan=4, sticky="w", pady=(2,0))

            def _open_chat_calibrator():
                import io as _io
                sw = self.root.winfo_screenwidth()
                sh = self.root.winfo_screenheight()
                try:
                    from PIL import ImageGrab as _IG, ImageTk as _ITK
                    _bg_shot = _IG.grab(all_screens=True)
                except Exception:
                    try:
                        from PIL import ImageGrab as _IG, ImageTk as _ITK
                        _bg_shot = _IG.grab()
                    except Exception:
                        _bg_shot = None
                ov = tk.Toplevel()
                ov.attributes("-fullscreen", True)
                ov.attributes("-topmost", True)
                ov.overrideredirect(True)
                cv = tk.Canvas(ov, cursor="crosshair", highlightthickness=0, bd=0, bg="black")
                cv.pack(fill="both", expand=True)
                if _bg_shot:
                    try:
                        _bg_shot_resized = _bg_shot.resize((sw, sh))
                        _bg_tk = _ITK.PhotoImage(_bg_shot_resized, master=ov)
                        cv.create_image(0, 0, anchor="nw", image=_bg_tk)
                        cv._bg_tk = _bg_tk
                    except Exception:
                        pass
                cv.create_rectangle(0, 0, sw, sh, fill="black", stipple="gray50", outline="")
                cv.create_text(sw//2, 32,
                               text="Draw a box over your Roblox chat  \u2022  Release mouse to preview  \u2022  Enter/click \u2713 to save  \u2022  Escape to cancel",
                               fill="white", font=("Segoe UI", 13, "bold"), anchor="center")
                _state = {"x0": 0, "y0": 0, "rect": None, "done": False,
                          "preview_win": None, "confirmed": False}
                def _close_preview():
                    if _state["preview_win"]:
                        try: _state["preview_win"].destroy()
                        except Exception: pass
                        _state["preview_win"] = None
                def _on_press(e):
                    _close_preview()
                    _state["x0"] = e.x; _state["y0"] = e.y
                    if _state["rect"]: cv.delete(_state["rect"])
                    cv.delete("sizelabel")
                    _state["rect"] = cv.create_rectangle(e.x, e.y, e.x, e.y, outline="#7c6af7", width=3, fill="")
                def _on_drag(e):
                    if _state["rect"]:
                        cv.coords(_state["rect"], _state["x0"], _state["y0"], e.x, e.y)
                        x1l = min(_state["x0"], e.x); y1l = min(_state["y0"], e.y)
                        x2l = max(_state["x0"], e.x); y2l = max(_state["y0"], e.y)
                        cv.delete("sizelabel")
                        cv.create_text((x1l+x2l)//2, max(y1l-16, 20),
                                       text=f"{x2l-x1l}\u00d7{y2l-y1l}px",
                                       fill="#5ce1e6", font=("Segoe UI", 10, "bold"),
                                       anchor="center", tags="sizelabel")
                def _on_release(e):
                    if not _state["rect"]: return
                    coords = cv.coords(_state["rect"])
                    if not coords or len(coords) != 4: return
                    rx1, ry1, rx2, ry2 = [int(v) for v in coords]
                    bx1 = min(rx1, rx2); by1 = min(ry1, ry2)
                    bx2 = max(rx1, rx2); by2 = max(ry1, ry2)
                    if bx2 - bx1 < 20 or by2 - by1 < 20: return
                    try:
                        from PIL import ImageGrab as _IG2, ImageTk as _ITK2
                        try:
                            snap = _IG2.grab(bbox=(bx1, by1, bx2, by2), all_screens=True)
                        except Exception:
                            snap = _IG2.grab(bbox=(bx1, by1, bx2, by2))
                        pw, ph = snap.size
                        max_w, max_h = 500, 350
                        scale = min(max_w / max(pw, 1), max_h / max(ph, 1), 1.0)
                        if scale < 1.0:
                            snap = snap.resize((int(pw * scale), int(ph * scale)))
                        snap_tk = _ITK2.PhotoImage(snap, master=ov)
                        _close_preview()
                        prev = tk.Toplevel(ov)
                        prev.title("Preview \u2014 does this look right?")
                        prev.attributes("-topmost", True)
                        prev.resizable(False, False)
                        pw2, ph2 = snap.size
                        px = sw // 2 - pw2 // 2
                        py = sh // 2 - ph2 // 2 - 60
                        prev.geometry(f"{pw2+20}x{ph2+80}+{px}+{py}")
                        prev.configure(bg="#1a1a2e")
                        _state["preview_win"] = prev
                        tk.Label(prev, text="Screenshot of selected region:",
                                 bg="#1a1a2e", fg="white",
                                 font=("Segoe UI", 10, "bold")).pack(pady=(8, 4))
                        lbl = tk.Label(prev, image=snap_tk, bg="#1a1a2e", relief="solid", bd=1)
                        lbl.image = snap_tk
                        lbl.pack(padx=10)
                        btn_f = tk.Frame(prev, bg="#1a1a2e")
                        btn_f.pack(pady=8)
                        tk.Button(btn_f, text="\u2713  Save this region",
                                  bg="#7c6af7", fg="white", font=("Segoe UI", 10, "bold"),
                                  relief="flat", padx=14, pady=5, cursor="hand2",
                                  command=lambda: _confirm()).pack(side="left", padx=6)
                        tk.Button(btn_f, text="\u2717  Redraw",
                                  bg="#333", fg="white", font=("Segoe UI", 10, "bold"),
                                  relief="flat", padx=14, pady=5, cursor="hand2",
                                  command=_close_preview).pack(side="left", padx=6)
                    except Exception as _ex:
                        print(f"[Calibrate] preview error: {_ex}")
                def _confirm(e=None):
                    if _state["done"]: return
                    _state["done"] = True
                    _close_preview()
                    coords = cv.coords(_state["rect"]) if _state["rect"] else None
                    ov.destroy()
                    if coords and len(coords) == 4:
                        rx1, ry1, rx2, ry2 = [int(v) for v in coords]
                        bx1 = min(rx1, rx2); by1 = min(ry1, ry2)
                        bx2 = max(rx1, rx2); by2 = max(ry1, ry2)
                        if bx2 - bx1 < 20 or by2 - by1 < 20:
                            self._ocr_scan_status.set("\u26a0 Region too small \u2014 try again")
                            return
                        self._ocr_chat_bbox = (bx1, by1, bx2, by2)
                        cx = (bx1+bx2)//2; cy = (by1+by2)//2
                        self._ocr_chat_xy   = (cx, cy)
                        self._ocr_coord_var.set(f"x1={bx1} y1={by1}  x2={bx2} y2={by2}  ({bx2-bx1}\u00d7{by2-by1}px)")
                        self._ocr_scan_status.set("\u2713 Chat region saved")
                        try:
                            if not self.cfg.has_section("Egg"): self.cfg["Egg"] = {}
                            self.cfg["Egg"]["chat_x1"] = str(bx1)
                            self.cfg["Egg"]["chat_y1"] = str(by1)
                            self.cfg["Egg"]["chat_x2"] = str(bx2)
                            self.cfg["Egg"]["chat_y2"] = str(by2)
                            save_config(self.cfg)
                        except Exception as ex:
                            print(f"[Calibrate] save error: {ex}")
                    else:
                        self._ocr_scan_status.set("\u26a0 No region drawn \u2014 cancelled")
                def _cancel(e=None):
                    _state["done"] = True
                    _close_preview()
                    ov.destroy()
                    self._ocr_scan_status.set("Calibration cancelled")
                cv.bind("<ButtonPress-1>",   _on_press)
                cv.bind("<B1-Motion>",       _on_drag)
                cv.bind("<ButtonRelease-1>", _on_release)
                ov.bind("<Return>",          _confirm)
                ov.bind("<KP_Enter>",        _confirm)
                ov.bind("<Escape>",          _cancel)
                ov.focus_force()

