            def _open_eden_calibrator():
                sw = self.root.winfo_screenwidth()
                sh = self.root.winfo_screenheight()
                try:
                    from PIL import ImageGrab as _IG, ImageTk as _ITK
                    _bg_shot = _IG.grab(all_screens=True)
                except Exception:
                    try:
                        from PIL import ImageGrab as _IG, ImageTk as _ITK
                        _bg_shot = _IG.grab()
                    except Exception:
                        _bg_shot = None
                ov = tk.Toplevel()
                ov.attributes("-fullscreen", True)
                ov.attributes("-topmost", True)
                ov.overrideredirect(True)
                cv = tk.Canvas(ov, cursor="crosshair", highlightthickness=0, bd=0, bg="black")
                cv.pack(fill="both", expand=True)
                if _bg_shot:
                    try:
                        _bg_shot_resized = _bg_shot.resize((sw, sh))
                        _bg_tk = _ITK.PhotoImage(_bg_shot_resized, master=ov)
                        cv.create_image(0, 0, anchor="nw", image=_bg_tk)
                        cv._bg_tk = _bg_tk
                    except Exception:
                        pass
                cv.create_rectangle(0, 0, sw, sh, fill="black", stipple="gray50", outline="")
                cv.create_text(sw//2, 32,
                               text="Draw a box over the screen region to scan  \u2022  Release to preview  \u2022  Enter/\u2713 to save  \u2022  Escape to cancel",
                               fill="white", font=("Segoe UI", 13, "bold"), anchor="center")
                _st = {"x0": 0, "y0": 0, "rect": None, "done": False, "preview_win": None}
                def _close_prev():
                    if _st["preview_win"]:
                        try: _st["preview_win"].destroy()
                        except Exception: pass
                        _st["preview_win"] = None
                def _on_press(e):
                    _close_prev()
                    _st["x0"] = e.x; _st["y0"] = e.y
                    if _st["rect"]: cv.delete(_st["rect"])
                    cv.delete("sizelabel")
                    _st["rect"] = cv.create_rectangle(e.x, e.y, e.x, e.y, outline="#9900ff", width=3, fill="")
                def _on_drag(e):
                    if _st["rect"]:
                        cv.coords(_st["rect"], _st["x0"], _st["y0"], e.x, e.y)
                        x1l = min(_st["x0"], e.x); y1l = min(_st["y0"], e.y)
                        x2l = max(_st["x0"], e.x); y2l = max(_st["y0"], e.y)
                        cv.delete("sizelabel")
                        cv.create_text((x1l+x2l)//2, max(y1l-16, 20),
                                       text=f"{x2l-x1l}\u00d7{y2l-y1l}px",
                                       fill="#bf80ff", font=("Segoe UI", 10, "bold"),
                                       anchor="center", tags="sizelabel")
                def _on_release(e):
                    if not _st["rect"]: return
                    coords = cv.coords(_st["rect"])
                    if not coords or len(coords) != 4: return
                    rx1, ry1, rx2, ry2 = [int(v) for v in coords]
                    bx1 = min(rx1, rx2); by1 = min(ry1, ry2)
                    bx2 = max(rx1, rx2); by2 = max(ry1, ry2)
                    if bx2 - bx1 < 20 or by2 - by1 < 20: return
                    try:
                        from PIL import ImageGrab as _IG2, ImageTk as _ITK2
                        try:
                            snap = _IG2.grab(bbox=(bx1, by1, bx2, by2), all_screens=True)
                        except Exception:
                            snap = _IG2.grab(bbox=(bx1, by1, bx2, by2))
                        pw, ph = snap.size
                        max_w, max_h = 500, 350
                        scale = min(max_w / max(pw, 1), max_h / max(ph, 1), 1.0)
                        if scale < 1.0:
                            snap = snap.resize((int(pw * scale), int(ph * scale)))
                        snap_tk = _ITK2.PhotoImage(snap, master=ov)
                        _close_prev()
                        prev = tk.Toplevel(ov)
                        prev.title("Preview \u2014 does this look right?")
                        prev.attributes("-topmost", True)
                        prev.resizable(False, False)
                        pw2, ph2 = snap.size
                        px = sw // 2 - pw2 // 2
                        py = sh // 2 - ph2 // 2 - 60
                        prev.geometry(f"{pw2+20}x{ph2+80}+{px}+{py}")
                        prev.configure(bg="#1a1a2e")
                        _st["preview_win"] = prev
                        tk.Label(prev, text="Screenshot of selected region:",
                                 bg="#1a1a2e", fg="white",
                                 font=("Segoe UI", 10, "bold")).pack(pady=(8, 4))
                        lbl = tk.Label(prev, image=snap_tk, bg="#1a1a2e", relief="solid", bd=1)
                        lbl.image = snap_tk
                        lbl.pack(padx=10)
                        btn_f = tk.Frame(prev, bg="#1a1a2e")
                        btn_f.pack(pady=8)
                        tk.Button(btn_f, text="\u2713  Save this region",
                                  bg="#9900ff", fg="white", font=("Segoe UI", 10, "bold"),
                                  relief="flat", padx=14, pady=5, cursor="hand2",
                                  command=lambda: _confirm()).pack(side="left", padx=6)
                        tk.Button(btn_f, text="\u2717  Redraw",
                                  bg="#333", fg="white", font=("Segoe UI", 10, "bold"),
                                  relief="flat", padx=14, pady=5, cursor="hand2",
                                  command=_close_prev).pack(side="left", padx=6)
                    except Exception as _ex:
                        print(f"[EdenCalibrate] preview error: {_ex}")
                def _confirm(e=None):
                    if _st["done"]: return
                    _st["done"] = True
                    _close_prev()
                    coords = cv.coords(_st["rect"]) if _st["rect"] else None
                    ov.destroy()
                    if coords and len(coords) == 4:
                        rx1, ry1, rx2, ry2 = [int(v) for v in coords]
                        bx1 = min(rx1, rx2); by1 = min(ry1, ry2)
                        bx2 = max(rx1, rx2); by2 = max(ry1, ry2)
                        if bx2 - bx1 < 20 or by2 - by1 < 20:
                            self._eden_ocr_cal_status.set("\u26a0 Region too small \u2014 try again")
                            return
                        self._eden_ocr_bbox = (bx1, by1, bx2, by2)
                        self._eden_ocr_coord_var.set(
                            f"x1={bx1} y1={by1}  x2={bx2} y2={by2}  ({bx2-bx1}\u00d7{by2-by1}px)")
                        self._eden_ocr_cal_status.set("\u2713 Region saved")
                        try:
                            if not self.cfg.has_section("Eden"): self.cfg["Eden"] = {}
                            self.cfg["Eden"]["ocr_x1"] = str(bx1)
                            self.cfg["Eden"]["ocr_y1"] = str(by1)
                            self.cfg["Eden"]["ocr_x2"] = str(bx2)
                            self.cfg["Eden"]["ocr_y2"] = str(by2)
                            save_config(self.cfg)
                        except Exception as ex:
                            print(f"[EdenCalibrate] save error: {ex}")
                    else:
                        self._eden_ocr_cal_status.set("\u26a0 No region drawn \u2014 cancelled")
                def _cancel(e=None):
                    _st["done"] = True
                    _close_prev()
                    ov.destroy()
                    self._eden_ocr_cal_status.set("Calibration cancelled")
                cv.bind("<ButtonPress-1>",   _on_press)
                cv.bind("<B1-Motion>",       _on_drag)
                cv.bind("<ButtonRelease-1>", _on_release)
                ov.bind("<Return>",          _confirm)
                ov.bind("<KP_Enter>",        _confirm)
                ov.bind("<Escape>",          _cancel)
                ov.focus_force()

            def _reset_eden_bbox():
                sw = self.root.winfo_screenwidth()  or 1920
                sh = self.root.winfo_screenheight() or 1080
                self._eden_ocr_bbox = (0, 0, sw, sh)
                self._eden_ocr_coord_var.set(f"x1=0 y1=0  x2={sw} y2={sh}  ({sw}\u00d7{sh}px)  [full screen]")
                self._eden_ocr_cal_status.set("Reset to full screen")
                try:
                    if not self.cfg.has_section("Eden"): self.cfg["Eden"] = {}
                    for k, v in [("ocr_x1","0"),("ocr_y1","0"),("ocr_x2",str(sw)),("ocr_y2",str(sh))]:
                        self.cfg["Eden"][k] = v
                    save_config(self.cfg)
                except Exception: pass

            btn(esf, "\u270f  Calibrate Screen Region", _open_eden_calibrator, "#9900ff").grid(row=0, column=0, padx=(0,6))
            btn(esf, "Full Screen",                     _reset_eden_bbox,       BG3).grid(row=0, column=1)

            edf = tk.Frame(eoc, bg=BG2); edf.grid(row=5, column=0, columnspan=4, sticky="w", padx=12, pady=(6,2))
            tk.Label(edf, text="Re-detect delay:", bg=BG2, fg=TXT2, font=FONT_LABEL).pack(side="left")
            self.eden_ocr_delay_min = tk.StringVar(value=self.cfg.get("Eden","ocr_delay_min",fallback="2"))
            self.eden_ocr_delay_sec = tk.StringVar(value=self.cfg.get("Eden","ocr_delay_sec",fallback="0"))
            entry(edf, self.eden_ocr_delay_min, width=4).pack(side="left", padx=(6,2))
            tk.Label(edf, text="min", bg=BG2, fg=TXT3, font=FONT_LABEL).pack(side="left", padx=(0,8))
            entry(edf, self.eden_ocr_delay_sec, width=4).pack(side="left", padx=(0,2))
            tk.Label(edf, text="sec", bg=BG2, fg=TXT3, font=FONT_LABEL).pack(side="left")

            emf = tk.Frame(eoc, bg=BG2); emf.grid(row=6, column=0, columnspan=4, sticky="w", padx=12, pady=(4,10))

            def _toggle_eden_ocr():
                if self._eden_ocr_running:
                    self._eden_ocr_running = False
                    self._eden_ocr_btn_var.set("\u25b6  Start Eden OCR")
                    self._eden_ocr_btn.configure(bg=BG3, fg=TXT)
                    self._eden_ocr_status.set("OCR stopped.")
                else:
                    import shutil as _sh
                    tess_ok = (
                        _sh.which("tesseract") or
                        any(os.path.isfile(p) for p in [
                            r"C:\Program Files\Tesseract-OCR\tesseract.exe",
                            r"C:\Program Files (x86)\Tesseract-OCR\tesseract.exe",
                            os.path.expanduser(r"~\AppData\Local\Programs\Tesseract-OCR\tesseract.exe"),
                        ])
                    )
                    if not tess_ok:
                        self._eden_ocr_status.set("\u26a0 Tesseract not found \u2014 install it first")
                        return
                    self._eden_ocr_running = True
                    self._eden_ocr_btn_var.set("\u25a0  Stop Eden OCR")
                    self._eden_ocr_btn.configure(bg="#9900ff", fg="#ffffff")
                    self._eden_ocr_status.set("Scanning screen every 2s for Eden\u2026")
                    self._eden_ocr_tick()

            self._eden_ocr_btn = tk.Button(
                emf, textvariable=self._eden_ocr_btn_var, command=_toggle_eden_ocr,
                bg=BG3, fg=TXT, font=FONT_LABEL, relief="flat", bd=0,
                padx=14, pady=6, cursor="hand2",
                activebackground=BG2, activeforeground=TXT)
            self._eden_ocr_btn.pack(side="left")
            tk.Label(emf, textvariable=self._eden_ocr_status, bg=BG2, fg="#9900ff",
                     font=FONT_LABEL).pack(side="left", padx=(10,0))
            eoc.columnconfigure(0, weight=1)

